import { cx } from '@/utils/cx';
import { Label } from '@/components/atoms/Input/base/label';
import type { ReactNode } from 'react';

export interface FieldsetProps extends React.ComponentProps<'div'> {
  children: ReactNode;
  className?: string;
  title?: string;
  subtitle?: string;
  labelPosition?: 'top' | 'left';
}

export function Fieldset({
  children,
  title,
  subtitle,
  labelPosition = 'top',
  className = '',
  ...rest
}: FieldsetProps) {
  return (
    <div
      className={cx(
        'flex gap-3',
        labelPosition === 'left' ? 'flex-row flex-wrap' : 'flex-col',
        className,
      )}
      {...rest}
    >
      {title && (
        <div
          data-legend
          className={labelPosition === 'left' ? 'w-70' : undefined}
        >
          <Label className="text-sm text-secondary font-semibold">
            {title}
          </Label>
          {subtitle && <div className="text-sm text-tertiary">{subtitle}</div>}
        </div>
      )}

      <div className={'flex flex-col gap-3'}>{children}</div>
    </div>
  );
}
